import{_ as o,o as t,c as a,a2 as d}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 11 — Word Motions","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/11-word-motions.md","filePath":"chapters/11-word-motions.md"}'),r={name:"chapters/11-word-motions.md"};function n(i,e,s,c,l,h){return t(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="chapter-11-—-word-motions" tabindex="-1">Chapter 11 — Word Motions <a class="header-anchor" href="#chapter-11-—-word-motions" aria-label="Permalink to &quot;Chapter 11 — Word Motions&quot;">​</a></h1><blockquote><p><em>&quot;Words are the most natural unit of navigation in any language.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 15–20 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Word motions are among the most frequently used navigation commands in Vim.</p><p>They let you jump over entire words instead of moving character by character.</p><hr><h1 id="the-four-word-motions" tabindex="-1">The Four Word Motions <a class="header-anchor" href="#the-four-word-motions" aria-label="Permalink to &quot;The Four Word Motions&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Motion</th><th>Action</th></tr></thead><tbody><tr><td><code>w</code></td><td>Forward to <strong>beginning</strong> of next word</td></tr><tr><td><code>b</code></td><td>Backward to <strong>beginning</strong> of word</td></tr><tr><td><code>e</code></td><td>Forward to <strong>end</strong> of word</td></tr><tr><td><code>ge</code></td><td>Backward to <strong>end</strong> of word</td></tr></tbody></table><h2 id="visual-diagram" tabindex="-1">Visual Diagram <a class="header-anchor" href="#visual-diagram" aria-label="Permalink to &quot;Visual Diagram&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>This is an example sentence</span></span>\n<span class="line"><span>^    ^  ^   ^       ^</span></span>\n<span class="line"><span>|    |  |   |       |</span></span>\n<span class="line"><span>|    |  |   |       w → beginning of &quot;sentence&quot;</span></span>\n<span class="line"><span>|    |  |   w → beginning of &quot;example&quot;</span></span>\n<span class="line"><span>|    |  w → beginning of &quot;an&quot;</span></span>\n<span class="line"><span>|    w → beginning of &quot;is&quot;</span></span>\n<span class="line"><span>w → beginning of &quot;This&quot;</span></span></code></pre></div><hr><h1 id="word-vs-word" tabindex="-1">Word vs WORD <a class="header-anchor" href="#word-vs-word" aria-label="Permalink to &quot;Word vs WORD&quot;">​</a></h1><h2 id="word-w-b-e" tabindex="-1">Word (<code>w</code>, <code>b</code>, <code>e</code>) <a class="header-anchor" href="#word-w-b-e" aria-label="Permalink to &quot;Word (`w`, `b`, `e`)&quot;">​</a></h2><p>A <strong>word</strong> is a sequence of letters, digits, or underscores.</p><p>Words are separated by:</p><ul><li>spaces</li><li>punctuation (<code>.</code>, <code>,</code>, <code>;</code>, <code>-</code>, <code>_</code>, etc.)</li><li>special characters</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hello-world foo.bar</span></span></code></pre></div><p>Using <code>w</code>:</p><ol><li><code>hello</code></li><li><code>-</code></li><li><code>world</code></li><li><code></code></li><li><code>foo</code></li><li><code>.</code></li><li><code>bar</code></li></ol><h2 id="word-w-b-e-1" tabindex="-1">WORD (<code>W</code>, <code>B</code>, <code>E</code>) <a class="header-anchor" href="#word-w-b-e-1" aria-label="Permalink to &quot;WORD (`W`, `B`, `E`)&quot;">​</a></h2><p>A <strong>WORD</strong> is a sequence of non-blank characters.</p><p>WORDs are separated <strong>only by spaces</strong>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>hello-world foo.bar</span></span></code></pre></div><p>Using <code>W</code>:</p><ol><li><code>hello-world</code></li><li><code>foo.bar</code></li></ol><hr><h1 id="when-to-use-which" tabindex="-1">When to Use Which <a class="header-anchor" href="#when-to-use-which" aria-label="Permalink to &quot;When to Use Which&quot;">​</a></h1><h2 id="use-w-b-e-when" tabindex="-1">Use <code>w</code> / <code>b</code> / <code>e</code> when: <a class="header-anchor" href="#use-w-b-e-when" aria-label="Permalink to &quot;Use `w` / `b` / `e` when:&quot;">​</a></h2><ul><li>Navigating code</li><li>Editing function names: <code>hello_world</code></li><li>Moving through paths: <code>src/components/Button.tsx</code></li><li>Deleting words precisely</li></ul><h2 id="use-w-b-e-when-1" tabindex="-1">Use <code>W</code> / <code>B</code> / <code>E</code> when: <a class="header-anchor" href="#use-w-b-e-when-1" aria-label="Permalink to &quot;Use `W` / `B` / `E` when:&quot;">​</a></h2><ul><li>Skipping large chunks quickly</li><li>Navigating prose with punctuation</li><li>You don&#39;t care about punctuation boundaries</li></ul><hr><h1 id="word-motions-with-counts" tabindex="-1">Word Motions with Counts <a class="header-anchor" href="#word-motions-with-counts" aria-label="Permalink to &quot;Word Motions with Counts&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>3w</code></td><td>Forward 3 words</td></tr><tr><td><code>5b</code></td><td>Backward 5 words</td></tr><tr><td><code>2e</code></td><td>Forward to end of 2nd word</td></tr><tr><td><code>3ge</code></td><td>Backward to end of 3rd word</td></tr></tbody></table><hr><h1 id="combining-with-operators" tabindex="-1">Combining with Operators <a class="header-anchor" href="#combining-with-operators" aria-label="Permalink to &quot;Combining with Operators&quot;">​</a></h1><p>Word motions become powerful when combined with operators:</p><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>dw</code></td><td>Delete word (from cursor to next word)</td></tr><tr><td><code>d3w</code></td><td>Delete 3 words</td></tr><tr><td><code>db</code></td><td>Delete backward word</td></tr><tr><td><code>cw</code></td><td>Change word (to end of current word)</td></tr><tr><td><code>c2w</code></td><td>Change 2 words</td></tr><tr><td><code>yw</code></td><td>Yank word</td></tr><tr><td><code>y3w</code></td><td>Yank 3 words</td></tr></tbody></table><h2 id="important-difference" tabindex="-1">Important Difference <a class="header-anchor" href="#important-difference" aria-label="Permalink to &quot;Important Difference&quot;">​</a></h2><ul><li><code>dw</code> deletes from cursor to the beginning of the next word.</li><li><code>diw</code> (delete inner word) deletes the entire word under the cursor.</li></ul><p>We&#39;ll cover text objects like <code>iw</code> (inner word) in Part V.</p><hr><h1 id="edge-cases" tabindex="-1">Edge Cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge Cases&quot;">​</a></h1><h2 id="cursor-in-the-middle-of-a-word" tabindex="-1">Cursor in the Middle of a Word <a class="header-anchor" href="#cursor-in-the-middle-of-a-word" aria-label="Permalink to &quot;Cursor in the Middle of a Word&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span>\n<span class="line"><span>    ^</span></span>\n<span class="line"><span>    cursor</span></span></code></pre></div><p><code>dw</code> → deletes only <code>lo World</code> (from cursor onward).</p><p>Not the entire word. To delete the whole word, use <code>diw</code>.</p><h2 id="empty-lines" tabindex="-1">Empty Lines <a class="header-anchor" href="#empty-lines" aria-label="Permalink to &quot;Empty Lines&quot;">​</a></h2><p>Word motions skip empty lines.</p><h2 id="end-of-file" tabindex="-1">End of File <a class="header-anchor" href="#end-of-file" aria-label="Permalink to &quot;End of File&quot;">​</a></h2><p><code>w</code> at the last word → can&#39;t move forward.</p><hr><h1 id="practice" tabindex="-1">Practice <a class="header-anchor" href="#practice" aria-label="Permalink to &quot;Practice&quot;">​</a></h1><p>Open a file and try:</p><ol><li>Navigate through a paragraph using <code>w</code> only.</li><li>Navigate backward using <code>b</code>.</li><li>Move to the end of each word using <code>e</code>.</li><li>Use <code>3w</code>, <code>5b</code>, <code>2e</code> to jump larger distances.</li><li>Delete words using <code>dw</code> and <code>diw</code>.</li><li>Copy words using <code>yw</code>.</li></ol><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Motion</th><th>Forward/Backward</th><th>To Beginning/End</th></tr></thead><tbody><tr><td><code>w</code></td><td>Forward</td><td>Beginning</td></tr><tr><td><code>b</code></td><td>Backward</td><td>Beginning</td></tr><tr><td><code>e</code></td><td>Forward</td><td>End</td></tr><tr><td><code>ge</code></td><td>Backward</td><td>End</td></tr></tbody></table><ul><li>Use lowercase for word boundaries (punctuation-aware).</li><li>Use uppercase for WORD boundaries (space-only).</li></ul><hr><h1 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h1><ul><li>Word motions jump over text faster than character motions.</li><li><code>w</code>/<code>b</code> jump to word beginnings; <code>e</code>/<code>ge</code> jump to word endings.</li><li>W (uppercase) treats everything until a space as one WORD.</li><li>Combine with <code>d</code>, <code>c</code>, <code>y</code> for powerful editing.</li><li><code>dw</code> deletes from cursor—not the whole word; use <code>diw</code> for that.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Find a paragraph of text and count how many <code>w</code> moves it takes to cross it.</li><li>Practice the difference between <code>dw</code> and <code>diw</code>.</li><li>Use <code>W</code> across a sentence with punctuation and note the difference.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./12-line-motions.html"><strong>Chapter 12 — Line Motions</strong></a></p><p>Master navigating to the beginnings and ends of lines—indispensable for editing code.</p>',72)])])}const w=o(r,[["render",n]]);export{u as __pageData,w as default};
